import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import api from '../../services/api';

const isAvailable = (seat) => seat.is_available === true || seat.is_available === 1;
const classLabel = (value) => String(value || '').replace('_', ' ');

const SeatSelection = () => {
  const { scheduleId } = useParams();
  const navigate = useNavigate();
  const [schedule, setSchedule] = useState(null);
  const [seats, setSeats] = useState([]);
  const [selected, setSelected] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [reserving, setReserving] = useState(false);

  const load = async () => {
    setLoading(true); setError('');
    try {
      const [scheduleRes, seatsRes] = await Promise.all([
        api.get(`/schedules/${scheduleId}`),
        api.get(`/seats/schedule/${scheduleId}`),
      ]);
      setSchedule(scheduleRes.data.data);
      setSeats(seatsRes.data.data || []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load seat map.');
    } finally { setLoading(false); }
  };

  useEffect(() => { load(); }, [scheduleId]);

  const selectedSeats = useMemo(() => seats.filter((s) => selected.includes(s.seat_id)), [seats, selected]);
  const total = useMemo(() => selectedSeats.reduce((sum, s) => sum + Number(schedule?.base_price || 0) * Number(s.price_multiplier || 1), 0), [selectedSeats, schedule]);

  const toggleSeat = (seat) => {
    if (!isAvailable(seat)) return;
    setSelected((prev) => prev.includes(seat.seat_id) ? prev.filter((id) => id !== seat.seat_id) : [...prev, seat.seat_id]);
  };

  const proceed = async () => {
    if (!selected.length) { setError('Please select at least one seat.'); return; }
    setReserving(true); setError('');
    try {
      await api.post('/seats/reserve', { seat_ids: selected });
      navigate('/bookings/create', { state: { schedule, selectedSeats, totalAmount: total } });
    } catch (err) {
      setError(err.response?.data?.message || 'Seat reserve failed. Refresh and try again.');
      load();
    } finally { setReserving(false); }
  };

  const grouped = seats.reduce((acc, seat) => {
    const key = seat.seat_class || 'other';
    acc[key] = acc[key] || [];
    acc[key].push(seat);
    return acc;
  }, {});

  if (loading) return <div className="loading">Loading seat map...</div>;

  return (
    <div className="page-container">
      <div className="page-header"><div><h1>Select Seats</h1><p>{schedule?.flight_number} — {schedule?.departure_city} to {schedule?.destination_city}</p></div><button className="btn-secondary" onClick={load}>Refresh</button></div>
      {error && <div className="alert alert-error">{error}</div>}
      <div className="card summary-card"><strong>Date:</strong> {String(schedule?.flight_date || '').split('T')[0]} &nbsp; <strong>Gate:</strong> {schedule?.gate_number || 'N/A'} &nbsp; <strong>Base price:</strong> ${Number(schedule?.base_price || 0).toLocaleString()}</div>
      <div className="seat-legend"><span><i className="seat available"></i> Available</span><span><i className="seat selected"></i> Selected</span><span><i className="seat booked"></i> Booked/Hold</span></div>
      <div className="card">
        {Object.entries(grouped).map(([klass, klassSeats]) => <div key={klass} className="seat-section"><h3>{classLabel(klass)} class</h3><div className="seat-grid">{klassSeats.map((seat) => <button type="button" key={seat.seat_id} className={`seat ${isAvailable(seat) ? 'available' : 'booked'} ${selected.includes(seat.seat_id) ? 'selected' : ''}`} onClick={() => toggleSeat(seat)} title={`${seat.seat_number} - ${klass}`}>{seat.seat_number}</button>)}</div></div>)}
      </div>
      <div className="card summary-card"><h3>Booking Summary</h3><p><strong>Selected:</strong> {selectedSeats.map(s => `${s.seat_number} (${classLabel(s.seat_class)})`).join(', ') || 'None'}</p><p><strong>Total:</strong> ${total.toLocaleString()}</p><button className="btn-primary" disabled={reserving || !selected.length} onClick={proceed}>{reserving ? 'Reserving...' : 'Proceed to Booking'}</button></div>
    </div>
  );
};

export default SeatSelection;
